export const slugify = (text) => {
  return text
    .toString()
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '-')
    .replace(/[^\w\-]+/g, '')
    .replace(/\-\-+/g, '-')
    .replace(/^-+/, '')
    .replace(/-+$/, '');
};

export const formatMb = (mb) => {
  if (mb === null || mb === undefined) return '--';
  if (mb >= 1024) return `${(mb / 1024).toFixed(1)} GB`;
  return `${Math.round(mb)} MB`;
};

export const formatAutoUnloadStatus = (timeoutSeconds, countdownSeconds) => {
  if (timeoutSeconds === 0) {
    return 'Disabled';
  }

  let status = `${timeoutSeconds}s`;
  if (countdownSeconds !== null && countdownSeconds !== undefined) {
    if (countdownSeconds <= 0) {
      status += ' (Unloading now...)';
    } else {
      status += ` (Unloading in ${countdownSeconds}s)`;
    }
  }

  return status;
};

export const getTimeDifference = (date) => {
  if (!date) return '--';
  const now = new Date();
  const diff = Math.floor((now - date) / 1000);

  if (diff < 0) return '0s ago';
  if (diff < 60) return `${diff}s ago`;
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return `${Math.floor(diff / 86400)}d ago`;
};
